function oppSlug(title) {
  return title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/-+$/, '').substring(0, 100);
}

function oppDesc(about, eligibility, benefits, howToApply) {
  return `
<h3>About This ${about.type}</h3>
<p>${about.body}</p>

<h3>Eligibility</h3>
<ul>${eligibility.map(e => `<li>${e}</li>`).join('\n')}</ul>

<h3>Benefits</h3>
<ul>${benefits.map(b => `<li>${b}</li>`).join('\n')}</ul>

<h3>How to Apply</h3>
<p>${howToApply}</p>
`.trim();
}

